sql:
SELECT MAX(total_viewers) AS max_total_viewers
FROM total_viewers
WHERE total_rating_share = (SELECT MAX(total_rating_share) FROM total_viewers);

SELECT episode_id, MAX(dvr_rating_share) AS max_dvr_rating_share
FROM dvr
GROUP BY episode_id;

SELECT total_viewers, total_rating_share, total_viewers_date
FROM total_viewers
WHERE total_viewers = (SELECT MAX(total_viewers) FROM total_viewers);

